import React, { useRef, useEffect } from 'react';

const InputArea = ({ inputMessage, setInputMessage, sendMessage, isLoading }) => {
  const textareaRef = useRef(null);

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const handleInput = (e) => {
    setInputMessage(e.target.value);
    
    // Auto-resize textarea
    const textarea = textareaRef.current;
    if (textarea) {
      textarea.style.height = 'auto';
      textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
    }
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
    }
  }, [inputMessage]);

  return (
    <div className="input-area">
      <div className="input-container">
        <div className="input-wrapper">
          <textarea
            ref={textareaRef}
            className="chat-input"
            placeholder="Ask me anything about any subject... I'm here to help you learn! 🌟"
            value={inputMessage}
            onChange={handleInput}
            onKeyPress={handleKeyPress}
            disabled={isLoading}
            rows="1"
          />
          <button
            className="send-button"
            onClick={sendMessage}
            disabled={isLoading || !inputMessage.trim()}
          >
            {isLoading ? (
              <div className="spinner-border spinner-border-sm" style={{ width: '16px', height: '16px' }}>
                <span className="visually-hidden">Loading...</span>
              </div>
            ) : (
              '→'
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default InputArea;
